MOD = 10**9 + 7

def count_special_permutations(nums):
    nums.sort()
    n = len(nums)
    memo = {}

    def backtrack(mask, last):
        if mask == (1 << n) - 1:
            return 1
        if (mask, last) in memo:
            return memo[(mask, last)]

        total = 0
        for i in range(n):
            if not (mask & (1 << i)):
                if nums[i] % last == 0 or last % nums[i] == 0:
                    total += backtrack(mask | (1 << i), nums[i])
                    total %= MOD
        memo[(mask, last)] = total
        return total

    return backtrack(0, 0)
